export const questions: Question[] = [
    { id: "y1ht3-001", topicRef: "y1ht3", topicTitle: "Critical Regions 01", yearCreated: 2026, examStyle: false, marks: 1, difficulty: "Foundation", tags: ["definition", "critical region"], questionText: "Define what is meant by a critical region in the context of a hypothesis test.", workedSolution: { steps: [{ stepNumber: 1, description: "State the definition.", workingLatex: "\\text{A critical region is the set of values of the test statistic for which the null hypothesis is rejected.}", explanation: "If the observed test statistic falls in the critical region, we reject the null hypothesis." }], finalAnswer: "A critical region is the set of all values of the test statistic that would cause the null hypothesis to be rejected." } },
    { id: "y1ht3-002", topicRef: "y1ht3", topicTitle: "Critical Regions 02", yearCreated: 2026, examStyle: false, marks: 1, difficulty: "Foundation", tags: ["definition", "critical value"], questionText: "Define what is meant by a critical value in the context of a hypothesis test.", workedSolution: { steps: [{ stepNumber: 1, description: "State the definition.", workingLatex: "\\text{A critical value is the boundary value of the critical region.}", explanation: "The critical value is the first value at which we would reject the null hypothesis. It lies on the boundary between the critical region and the acceptance region." }], finalAnswer: "A critical value is the first value to fall inside the critical region; it is the boundary value that separates the critical region from the acceptance region." } },
    { id: "y1ht3-003", topicRef: "y1ht3", topicTitle: "Critical Regions 03", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["critical region", "lower tail", "cumulative probability"], questionText: "A test uses \\(X \\sim B(15, p)\\) with \\(H_0: p = 0.4\\) and \\(H_1: p < 0.4\\) at the 5% significance level. Given that \\(P(X \\le 2) = 0.0271\\) and \\(P(X \\le 3) = 0.0905\\) under \\(H_0\\), state the critical region for this test.", workedSolution: { steps: [{ stepNumber: 1, description: "Check cumulative probabilities against 0.05.", workingLatex: "P(X \\le 2) = 0.0271 < 0.05", explanation: "" }, { stepNumber: 2, description: "Check the next value.", workingLatex: "P(X \\le 3) = 0.0905 > 0.05", explanation: "Since P(X <= 2) < 0.05 but P(X <= 3) > 0.05, the critical region is X <= 2." }], finalAnswer: "The critical region is \\(X \\le 2\\)." } },
    { id: "y1ht3-004", topicRef: "y1ht3", topicTitle: "Critical Regions 04", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["critical value", "lower tail"], questionText: "A test uses \\(X \\sim B(20, p)\\) with \\(H_0: p = 0.5\\) and \\(H_1: p < 0.5\\) at the 5% significance level. Given that \\(P(X \\le 5) = 0.0207\\) and \\(P(X \\le 6) = 0.0577\\) under \\(H_0\\), state the critical value for this test.", workedSolution: { steps: [{ stepNumber: 1, description: "Identify the largest value of c such that P(X <= c) < 0.05.", workingLatex: "P(X \\le 5) = 0.0207 < 0.05", explanation: "" }, { stepNumber: 2, description: "Check c + 1.", workingLatex: "P(X \\le 6) = 0.0577 > 0.05", explanation: "So the critical value is 5, meaning the critical region is X <= 5." }], finalAnswer: "The critical value is \\(5\\)." } },
    { id: "y1ht3-005", topicRef: "y1ht3", topicTitle: "Critical Regions 05", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["observed value", "critical region", "decision"], questionText: "The critical region for a test is \\(X \\le 3\\). The observed value of the test statistic is \\(X = 2\\). State whether the null hypothesis should be rejected.", workedSolution: { steps: [{ stepNumber: 1, description: "Compare the observed value to the critical region.", workingLatex: "X = 2 \\le 3", explanation: "The observed value 2 falls in the critical region X <= 3." }, { stepNumber: 2, description: "State the conclusion.", workingLatex: "\\text{Reject } H_0.", explanation: "Since the observed value lies in the critical region, we reject the null hypothesis." }], finalAnswer: "Since \\(2 \\le 3\\), the observed value lies in the critical region, so we reject \\(H_0\\)." } },
    { id: "y1ht3-006", topicRef: "y1ht3", topicTitle: "Critical Regions 06", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["observed value", "critical region", "decision"], questionText: "The critical region for a test is \\(X \\ge 14\\) where \\(X \\sim B(20, p)\\). The observed value is \\(X = 12\\). State whether the null hypothesis should be rejected.", workedSolution: { steps: [{ stepNumber: 1, description: "Compare the observed value to the critical region.", workingLatex: "X = 12 < 14", explanation: "The observed value 12 does not fall in the critical region X >= 14." }, { stepNumber: 2, description: "State the conclusion.", workingLatex: "\\text{Do not reject } H_0.", explanation: "Since the observed value does not lie in the critical region, we do not reject the null hypothesis." }], finalAnswer: "Since \\(12 < 14\\), the observed value does not lie in the critical region, so we do not reject \\(H_0\\)." } },
    { id: "y1ht3-007", topicRef: "y1ht3", topicTitle: "Critical Regions 07", yearCreated: 2026, examStyle: false, marks: 1, difficulty: "Foundation", tags: ["definition", "actual significance level"], questionText: "Define what is meant by the actual significance level of a hypothesis test.", workedSolution: { steps: [{ stepNumber: 1, description: "State the definition.", workingLatex: "\\text{The actual significance level is the probability of rejecting } H_0 \\text{ when } H_0 \\text{ is true.}", explanation: "For a discrete distribution, the actual significance level equals the probability of the test statistic falling in the critical region, which may differ from the nominal significance level." }], finalAnswer: "The actual significance level is the probability of incorrectly rejecting \\(H_0\\) when \\(H_0\\) is true. It equals the probability of the test statistic falling in the critical region." } },
    { id: "y1ht3-008", topicRef: "y1ht3", topicTitle: "Critical Regions 08", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["actual significance level", "critical region"], questionText: "The critical region for a one-tailed test is \\(X \\le 2\\), where \\(X \\sim B(15, 0.4)\\) under \\(H_0\\). Given that \\(P(X \\le 2) = 0.0271\\), state the actual significance level of the test.", workedSolution: { steps: [{ stepNumber: 1, description: "Identify the actual significance level.", workingLatex: "\\text{Actual significance level} = P(X \\le 2) = 0.0271", explanation: "The actual significance level is the probability of the test statistic falling in the critical region when H0 is true." }], finalAnswer: "The actual significance level is \\(0.0271\\) (or \\(2.71\\%\\))." } },
    { id: "y1ht3-009", topicRef: "y1ht3", topicTitle: "Critical Regions 09", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["critical region", "B(10,0.5)", "lower tail"], questionText: "The random variable \\(X \\sim B(10, 0.5)\\). Find the critical region for a test of \\(H_0: p = 0.5\\) against \\(H_1: p < 0.5\\) at the 5% significance level. You are given that \\(P(X \\le 0) = 0.0010\\), \\(P(X \\le 1) = 0.0107\\) and \\(P(X \\le 2) = 0.0547\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Check cumulative probabilities against 0.05.", workingLatex: "P(X \\le 1) = 0.0107 < 0.05", explanation: "" }, { stepNumber: 2, description: "Check the next value.", workingLatex: "P(X \\le 2) = 0.0547 > 0.05", explanation: "Since P(X <= 1) < 0.05 but P(X <= 2) > 0.05, the critical region is X <= 1." }], finalAnswer: "The critical region is \\(X \\le 1\\)." } },
    { id: "y1ht3-010", topicRef: "y1ht3", topicTitle: "Critical Regions 10", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["critical region", "upper tail", "B(10,0.5)"], questionText: "The random variable \\(X \\sim B(10, 0.5)\\). Find the critical region for a test of \\(H_0: p = 0.5\\) against \\(H_1: p > 0.5\\) at the 5% significance level. You are given that \\(P(X \\ge 8) = 0.0547\\) and \\(P(X \\ge 9) = 0.0107\\).", workedSolution: { steps: [{ stepNumber: 1, description: "For an upper-tail test, find the smallest c such that P(X >= c) <= 0.05.", workingLatex: "P(X \\ge 8) = 0.0547 > 0.05", explanation: "" }, { stepNumber: 2, description: "Check the next value.", workingLatex: "P(X \\ge 9) = 0.0107 < 0.05", explanation: "Since P(X >= 9) < 0.05 but P(X >= 8) > 0.05, the critical region is X >= 9." }], finalAnswer: "The critical region is \\(X \\ge 9\\)." } },
    { id: "y1ht3-011", topicRef: "y1ht3", topicTitle: "Critical Regions 11", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Standard", tags: ["critical region", "lower tail", "5%"], questionText: "The random variable \\(X \\sim B(20, 0.3)\\). Find the critical region for a test of \\(H_0: p = 0.3\\) against \\(H_1: p < 0.3\\) at the 5% significance level. You are given that \\(P(X \\le 2) = 0.0355\\) and \\(P(X \\le 3) = 0.1071\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Compare cumulative probabilities to 0.05.", workingLatex: "P(X \\le 2) = 0.0355 < 0.05", explanation: "" }, { stepNumber: 2, description: "Check the next cumulative probability.", workingLatex: "P(X \\le 3) = 0.1071 > 0.05", explanation: "Since P(X <= 2) < 0.05 but P(X <= 3) > 0.05, the critical region is X <= 2." }], finalAnswer: "The critical region is \\(X \\le 2\\)." } },
    { id: "y1ht3-012", topicRef: "y1ht3", topicTitle: "Critical Regions 12", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Standard", tags: ["critical region", "lower tail", "1%"], questionText: "The random variable \\(X \\sim B(20, 0.3)\\). Find the critical region for a test of \\(H_0: p = 0.3\\) against \\(H_1: p < 0.3\\) at the 1% significance level. You are given that \\(P(X \\le 0) = 0.0008\\), \\(P(X \\le 1) = 0.0076\\) and \\(P(X \\le 2) = 0.0355\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Compare cumulative probabilities to 0.01.", workingLatex: "P(X \\le 1) = 0.0076 < 0.01", explanation: "" }, { stepNumber: 2, description: "Check the next value.", workingLatex: "P(X \\le 2) = 0.0355 > 0.01", explanation: "Since P(X <= 1) < 0.01 but P(X <= 2) > 0.01, the critical region is X <= 1." }], finalAnswer: "The critical region is \\(X \\le 1\\)." } },
    { id: "y1ht3-013", topicRef: "y1ht3", topicTitle: "Critical Regions 13", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Standard", tags: ["critical region", "upper tail", "5%"], questionText: "The random variable \\(X \\sim B(20, 0.3)\\). Find the critical region for a test of \\(H_0: p = 0.3\\) against \\(H_1: p > 0.3\\) at the 5% significance level. You are given that \\(P(X \\le 9) = 0.9520\\) and \\(P(X \\le 10) = 0.9829\\).", workedSolution: { steps: [{ stepNumber: 1, description: "For an upper-tail test, find c such that P(X >= c) <= 0.05, which is equivalent to P(X <= c-1) >= 0.95.", workingLatex: "P(X \\le 9) = 0.9520 \\ge 0.95", explanation: "So P(X >= 10) = 1 - 0.9520 = 0.0480 <= 0.05." }, { stepNumber: 2, description: "Check whether a smaller critical value also works.", workingLatex: "P(X \\le 8) = 1 - P(X \\ge 9)", explanation: "We need P(X >= 9). Since P(X <= 9) = 0.9520, we have P(X >= 10) = 0.0480. We also check: P(X <= 8) would need to be >= 0.95 for X >= 9 to work. Since P(X <= 9) = 0.9520 and P(X = 9) > 0, P(X <= 8) < 0.9520, so we need to verify. However, using the given values: P(X >= 10) = 1 - 0.9520 = 0.0480 <= 0.05, and P(X >= 11) = 1 - 0.9829 = 0.0171 <= 0.05 but would give a smaller critical region. We want the largest critical region, so the critical value is 10." }], finalAnswer: "The critical region is \\(X \\ge 10\\)." } },
    { id: "y1ht3-014", topicRef: "y1ht3", topicTitle: "Critical Regions 14", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["two-tailed", "critical region", "5%"], questionText: "The random variable \\(X \\sim B(20, 0.5)\\). Find the critical region for a two-tailed test of \\(H_0: p = 0.5\\) against \\(H_1: p \\ne 0.5\\) at the 5% significance level. You are given that \\(P(X \\le 5) = 0.0207\\), \\(P(X \\le 6) = 0.0577\\), \\(P(X \\ge 15) = 0.0207\\) and \\(P(X \\ge 14) = 0.0577\\).", workedSolution: { steps: [{ stepNumber: 1, description: "For a two-tailed test at 5%, each tail must have probability at most 2.5% = 0.025.", workingLatex: "\\text{Lower tail: } P(X \\le 5) = 0.0207 < 0.025", explanation: "" }, { stepNumber: 2, description: "Check the next lower value.", workingLatex: "P(X \\le 6) = 0.0577 > 0.025", explanation: "So the lower critical region is X <= 5." }, { stepNumber: 3, description: "Upper tail.", workingLatex: "P(X \\ge 15) = 0.0207 < 0.025", explanation: "" }, { stepNumber: 4, description: "Check the next upper value.", workingLatex: "P(X \\ge 14) = 0.0577 > 0.025", explanation: "So the upper critical region is X >= 15." }], finalAnswer: "The critical region is \\(X \\le 5\\) or \\(X \\ge 15\\)." } },
    { id: "y1ht3-015", topicRef: "y1ht3", topicTitle: "Critical Regions 15", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["two-tailed", "critical region", "actual significance level"], questionText: "The random variable \\(X \\sim B(20, 0.5)\\). The critical region for a two-tailed test is \\(X \\le 5\\) or \\(X \\ge 15\\). Given that \\(P(X \\le 5) = 0.0207\\) and \\(P(X \\ge 15) = 0.0207\\), find the actual significance level of this test.", workedSolution: { steps: [{ stepNumber: 1, description: "The actual significance level is the total probability of both tails.", workingLatex: "\\text{Actual significance level} = P(X \\le 5) + P(X \\ge 15)", explanation: "" }, { stepNumber: 2, description: "Substitute.", workingLatex: "= 0.0207 + 0.0207 = 0.0414", explanation: "" }], finalAnswer: "The actual significance level is \\(0.0414\\) (or \\(4.14\\%\\))." } },
    { id: "y1ht3-016", topicRef: "y1ht3", topicTitle: "Critical Regions 16", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Standard", tags: ["actual significance level", "discrete", "explanation"], questionText: "Explain why the actual significance level of a hypothesis test using a binomial distribution may differ from the stated significance level.", workedSolution: { steps: [{ stepNumber: 1, description: "Explain the key reason.", workingLatex: "\\text{The binomial distribution is discrete.}", explanation: "Because the binomial distribution is discrete, it is generally not possible to find a critical region whose probability is exactly equal to the significance level." }, { stepNumber: 2, description: "Clarify the consequence.", workingLatex: "\\text{The actual significance level is the closest probability that does not exceed the nominal level.}", explanation: "We choose the largest critical region such that its probability does not exceed the stated significance level, so the actual level is usually less than the nominal level." }], finalAnswer: "The binomial distribution is discrete, so it is usually impossible to find a critical region with probability exactly equal to the nominal significance level. The actual significance level is the probability of the critical region, which is as close as possible to but does not exceed the nominal level." } },
    { id: "y1ht3-017", topicRef: "y1ht3", topicTitle: "Critical Regions 17", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["critical region", "actual significance level", "one-tailed"], questionText: "The random variable \\(X \\sim B(25, 0.2)\\). Find the critical region for a test of \\(H_0: p = 0.2\\) against \\(H_1: p < 0.2\\) at the 5% significance level and state the actual significance level. You are given that \\(P(X \\le 1) = 0.0274\\), \\(P(X \\le 2) = 0.0982\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Compare cumulative probabilities to 0.05.", workingLatex: "P(X \\le 1) = 0.0274 < 0.05", explanation: "" }, { stepNumber: 2, description: "Check the next value.", workingLatex: "P(X \\le 2) = 0.0982 > 0.05", explanation: "So the critical region is X <= 1." }, { stepNumber: 3, description: "State the actual significance level.", workingLatex: "\\text{Actual significance level} = P(X \\le 1) = 0.0274", explanation: "This is 2.74%, which is less than the nominal 5%." }], finalAnswer: "The critical region is \\(X \\le 1\\). The actual significance level is \\(0.0274\\) (\\(2.74\\%\\))." } },
    { id: "y1ht3-018", topicRef: "y1ht3", topicTitle: "Critical Regions 18", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["two-tailed", "critical region", "10%"], questionText: "The random variable \\(X \\sim B(20, 0.3)\\). Find the critical region for a two-tailed test of \\(H_0: p = 0.3\\) against \\(H_1: p \\ne 0.3\\) at the 10% significance level. You are given: \\(P(X \\le 2) = 0.0355\\), \\(P(X \\le 3) = 0.1071\\), \\(P(X \\ge 10) = 0.0480\\) and \\(P(X \\ge 9) = 0.1133\\).", workedSolution: { steps: [{ stepNumber: 1, description: "For a two-tailed test at 10%, each tail must have probability at most 5% = 0.05.", workingLatex: "\\text{Lower tail: } P(X \\le 2) = 0.0355 < 0.05", explanation: "" }, { stepNumber: 2, description: "Check the next lower value.", workingLatex: "P(X \\le 3) = 0.1071 > 0.05", explanation: "So the lower critical region is X <= 2." }, { stepNumber: 3, description: "Upper tail.", workingLatex: "P(X \\ge 10) = 0.0480 < 0.05", explanation: "" }, { stepNumber: 4, description: "Check the next upper value.", workingLatex: "P(X \\ge 9) = 0.1133 > 0.05", explanation: "So the upper critical region is X >= 10." }], finalAnswer: "The critical region is \\(X \\le 2\\) or \\(X \\ge 10\\)." } },
    { id: "y1ht3-019", topicRef: "y1ht3", topicTitle: "Critical Regions 19", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["critical region", "observed value", "conclusion", "context"], questionText: "A factory claims that 30% of its products are defective. A quality control inspector tests 20 items and finds that 2 are defective. The critical region for a one-tailed test at the 5% level, where \\(X \\sim B(20, 0.3)\\) and \\(H_1: p < 0.3\\), is \\(X \\le 2\\). State whether there is sufficient evidence to reject the factory's claim.", workedSolution: { steps: [{ stepNumber: 1, description: "Compare the observed value to the critical region.", workingLatex: "X = 2 \\le 2", explanation: "The observed value 2 falls in the critical region X <= 2." }, { stepNumber: 2, description: "State the conclusion in context.", workingLatex: "\\text{Reject } H_0.", explanation: "There is sufficient evidence at the 5% significance level to suggest that the proportion of defective products is less than 30%." }], finalAnswer: "Since \\(X = 2\\) lies in the critical region \\(X \\le 2\\), we reject \\(H_0\\). There is sufficient evidence at the 5% significance level to suggest that the defective rate is less than 30%." } },
    { id: "y1ht3-020", topicRef: "y1ht3", topicTitle: "Critical Regions 20", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["critical region", "observed value", "conclusion", "context"], questionText: "A doctor believes that a new treatment is more effective than the current treatment which has a 40% success rate. She trials the new treatment on 15 patients and 10 are successfully treated. The critical region for a one-tailed test at the 5% level, where \\(X \\sim B(15, 0.4)\\) and \\(H_1: p > 0.4\\), is \\(X \\ge 10\\). State whether there is sufficient evidence to support the doctor's belief.", workedSolution: { steps: [{ stepNumber: 1, description: "Compare the observed value to the critical region.", workingLatex: "X = 10 \\ge 10", explanation: "The observed value 10 falls in the critical region X >= 10." }, { stepNumber: 2, description: "State the conclusion in context.", workingLatex: "\\text{Reject } H_0.", explanation: "" }], finalAnswer: "Since \\(X = 10\\) lies in the critical region \\(X \\ge 10\\), we reject \\(H_0\\). There is sufficient evidence at the 5% significance level to support the doctor's belief that the new treatment is more effective than the current 40% success rate." } },
    { id: "y1ht3-021", topicRef: "y1ht3", topicTitle: "Critical Regions 21", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["two-tailed", "actual significance level", "10%"], questionText: "The random variable \\(X \\sim B(20, 0.3)\\). The critical region for a two-tailed test is \\(X \\le 2\\) or \\(X \\ge 10\\). Given that \\(P(X \\le 2) = 0.0355\\) and \\(P(X \\ge 10) = 0.0480\\), find the actual significance level of the test.", workedSolution: { steps: [{ stepNumber: 1, description: "Sum the probabilities of both tails.", workingLatex: "\\text{Actual significance level} = P(X \\le 2) + P(X \\ge 10)", explanation: "" }, { stepNumber: 2, description: "Calculate.", workingLatex: "= 0.0355 + 0.0480 = 0.0835", explanation: "" }], finalAnswer: "The actual significance level is \\(0.0835\\) (or \\(8.35\\%\\))." } },
    { id: "y1ht3-022", topicRef: "y1ht3", topicTitle: "Critical Regions 22", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["critical region", "upper tail", "1%"], questionText: "The random variable \\(X \\sim B(30, 0.25)\\). Find the critical region for a test of \\(H_0: p = 0.25\\) against \\(H_1: p > 0.25\\) at the 1% significance level. You are given: \\(P(X \\le 13) = 0.9918\\) and \\(P(X \\le 12) = 0.9784\\).", workedSolution: { steps: [{ stepNumber: 1, description: "For an upper-tail test at 1%, find c such that P(X >= c) <= 0.01.", workingLatex: "P(X \\ge 14) = 1 - P(X \\le 13) = 1 - 0.9918 = 0.0082", explanation: "" }, { stepNumber: 2, description: "Check whether a smaller critical value also works.", workingLatex: "P(X \\ge 13) = 1 - P(X \\le 12) = 1 - 0.9784 = 0.0216 > 0.01", explanation: "Since P(X >= 13) > 0.01 but P(X >= 14) <= 0.01, the critical region is X >= 14." }], finalAnswer: "The critical region is \\(X \\ge 14\\)." } },
    { id: "y1ht3-023", topicRef: "y1ht3", topicTitle: "Critical Regions 23", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["critical region", "context", "opinion poll"], questionText: "An opinion poll suggests that 35% of voters support a particular party. A researcher believes the true proportion has changed. She surveys 25 randomly selected voters and uses a two-tailed test at the 5% significance level with \\(X \\sim B(25, 0.35)\\). Given: \\(P(X \\le 4) = 0.0239\\), \\(P(X \\le 5) = 0.0636\\), \\(P(X \\ge 13) = 0.0442\\) and \\(P(X \\ge 14) = 0.0195\\). Find the critical region for this test.", workedSolution: { steps: [{ stepNumber: 1, description: "For a two-tailed test at 5%, each tail has at most 2.5%.", workingLatex: "\\text{Lower tail: } P(X \\le 4) = 0.0239 < 0.025", explanation: "" }, { stepNumber: 2, description: "Check next lower value.", workingLatex: "P(X \\le 5) = 0.0636 > 0.025", explanation: "So lower critical region is X <= 4." }, { stepNumber: 3, description: "Upper tail.", workingLatex: "P(X \\ge 14) = 0.0195 < 0.025", explanation: "" }, { stepNumber: 4, description: "Check next upper value.", workingLatex: "P(X \\ge 13) = 0.0442 > 0.025", explanation: "So upper critical region is X >= 14." }], finalAnswer: "The critical region is \\(X \\le 4\\) or \\(X \\ge 14\\)." } },
    { id: "y1ht3-024", topicRef: "y1ht3", topicTitle: "Critical Regions 24", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["comparing significance levels", "critical region"], questionText: "The random variable \\(X \\sim B(20, 0.5)\\). The critical region for a lower-tailed test at the 5% level is \\(X \\le 5\\) and the critical region at the 1% level is \\(X \\le 3\\). Given that \\(P(X \\le 5) = 0.0207\\) and \\(P(X \\le 3) = 0.0013\\), state the actual significance level at each level and comment on the difference.", workedSolution: { steps: [{ stepNumber: 1, description: "State the actual significance level at 5%.", workingLatex: "\\text{At 5\\%: actual significance level} = P(X \\le 5) = 0.0207", explanation: "" }, { stepNumber: 2, description: "State the actual significance level at 1%.", workingLatex: "\\text{At 1\\%: actual significance level} = P(X \\le 3) = 0.0013", explanation: "" }, { stepNumber: 3, description: "Comment on the difference.", workingLatex: "\\text{A lower significance level gives a smaller critical region, making it harder to reject } H_0.", explanation: "At the 1% level, we require stronger evidence to reject the null hypothesis." }], finalAnswer: "At 5%: actual significance level is \\(0.0207\\) with critical region \\(X \\le 5\\). At 1%: actual significance level is \\(0.0013\\) with critical region \\(X \\le 3\\). A lower significance level gives a smaller critical region, requiring stronger evidence to reject \\(H_0\\)." } },
    { id: "y1ht3-025", topicRef: "y1ht3", topicTitle: "Critical Regions 25", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["critical region", "medical context"], questionText: "A pharmaceutical company claims that a drug cures 60% of patients. A health authority suspects the drug is less effective than claimed and tests it on 18 patients. Using \\(X \\sim B(18, 0.6)\\) with \\(H_1: p < 0.6\\) at the 5% significance level, find the critical region. You are given: \\(P(X \\le 6) = 0.0203\\) and \\(P(X \\le 7) = 0.0596\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Compare cumulative probabilities to 0.05.", workingLatex: "P(X \\le 6) = 0.0203 < 0.05", explanation: "" }, { stepNumber: 2, description: "Check the next value.", workingLatex: "P(X \\le 7) = 0.0596 > 0.05", explanation: "Since P(X <= 6) < 0.05 but P(X <= 7) > 0.05, the critical region is X <= 6." }], finalAnswer: "The critical region is \\(X \\le 6\\). If 6 or fewer patients are cured out of 18, there is sufficient evidence at the 5% level to reject the company's claim." } },
    { id: "y1ht3-026", topicRef: "y1ht3", topicTitle: "Critical Regions 26", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["critical region", "two-tailed", "5%", "context"], questionText: "A manufacturer claims that 25% of items produced are premium quality. An inspector believes the proportion may have changed and takes a sample of 30 items. Using \\(X \\sim B(30, 0.25)\\) with \\(H_1: p \\ne 0.25\\) at the 5% significance level, find the critical region and the actual significance level. You are given: \\(P(X \\le 3) = 0.0493\\), \\(P(X \\le 2) = 0.0172\\), \\(P(X \\ge 12) = 0.0481\\) and \\(P(X \\ge 13) = 0.0216\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Each tail must have probability at most 2.5%.", workingLatex: "\\text{Lower tail: } P(X \\le 2) = 0.0172 < 0.025", explanation: "" }, { stepNumber: 2, description: "Check next lower value.", workingLatex: "P(X \\le 3) = 0.0493 > 0.025", explanation: "So lower critical region is X <= 2." }, { stepNumber: 3, description: "Upper tail.", workingLatex: "P(X \\ge 13) = 0.0216 < 0.025", explanation: "" }, { stepNumber: 4, description: "Check next upper value.", workingLatex: "P(X \\ge 12) = 0.0481 > 0.025", explanation: "So upper critical region is X >= 13." }, { stepNumber: 5, description: "Calculate actual significance level.", workingLatex: "\\text{Actual significance level} = P(X \\le 2) + P(X \\ge 13) = 0.0172 + 0.0216 = 0.0388", explanation: "" }], finalAnswer: "The critical region is \\(X \\le 2\\) or \\(X \\ge 13\\). The actual significance level is \\(0.0388\\) (\\(3.88\\%\\))." } },
    { id: "y1ht3-027", topicRef: "y1ht3", topicTitle: "Critical Regions 27", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["critical region", "observed value", "conclusion"], questionText: "The random variable \\(X \\sim B(25, 0.4)\\) under \\(H_0\\). The critical region for a one-tailed test (\\(H_1: p < 0.4\\)) at the 5% level is \\(X \\le 5\\). An observed value of \\(X = 6\\) is obtained. State the conclusion of the test, giving a reason.", workedSolution: { steps: [{ stepNumber: 1, description: "Compare the observed value to the critical region.", workingLatex: "X = 6 > 5", explanation: "The observed value 6 does not fall in the critical region X <= 5." }, { stepNumber: 2, description: "State the conclusion.", workingLatex: "\\text{Do not reject } H_0.", explanation: "" }], finalAnswer: "Since \\(X = 6\\) does not lie in the critical region \\(X \\le 5\\), we do not reject \\(H_0\\). There is insufficient evidence at the 5% level to suggest that \\(p < 0.4\\)." } },
    { id: "y1ht3-028", topicRef: "y1ht3", topicTitle: "Critical Regions 28", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["critical region", "actual significance level", "context"], questionText: "A teacher believes that fewer than 50% of students pass a particular exam. She takes a random sample of 12 students. Using \\(X \\sim B(12, 0.5)\\) with \\(H_1: p < 0.5\\) at the 10% significance level, find the critical region and state the actual significance level. You are given: \\(P(X \\le 3) = 0.0730\\), \\(P(X \\le 2) = 0.0193\\) and \\(P(X \\le 4) = 0.1938\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Compare cumulative probabilities to 0.10.", workingLatex: "P(X \\le 3) = 0.0730 < 0.10", explanation: "" }, { stepNumber: 2, description: "Check the next value.", workingLatex: "P(X \\le 4) = 0.1938 > 0.10", explanation: "So the critical region is X <= 3." }, { stepNumber: 3, description: "State the actual significance level.", workingLatex: "\\text{Actual significance level} = P(X \\le 3) = 0.0730", explanation: "" }], finalAnswer: "The critical region is \\(X \\le 3\\). The actual significance level is \\(0.0730\\) (\\(7.30\\%\\))." } },
    { id: "y1ht3-029", topicRef: "y1ht3", topicTitle: "Critical Regions 29", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["multi-part", "critical region", "actual significance level", "conclusion"], questionText: "The random variable \\(X \\sim B(25, 0.3)\\). A one-tailed test is conducted with \\(H_0: p = 0.3\\) and \\(H_1: p < 0.3\\) at the 5% significance level. You are given: \\(P(X \\le 3) = 0.0332\\) and \\(P(X \\le 4) = 0.0905\\). (a) Find the critical region. (b) State the actual significance level. (c) An observed value of \\(X = 3\\) is obtained. State the conclusion of the test in context.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Find the critical region.", workingLatex: "P(X \\le 3) = 0.0332 < 0.05 \\quad \\text{and} \\quad P(X \\le 4) = 0.0905 > 0.05", explanation: "So the critical region is X <= 3." }, { stepNumber: 2, description: "(b) State the actual significance level.", workingLatex: "\\text{Actual significance level} = P(X \\le 3) = 0.0332", explanation: "" }, { stepNumber: 3, description: "(c) Compare X = 3 to the critical region.", workingLatex: "X = 3 \\le 3 \\implies X = 3 \\text{ lies in the critical region.}", explanation: "" }, { stepNumber: 4, description: "State the conclusion.", workingLatex: "\\text{Reject } H_0.", explanation: "There is sufficient evidence at the 5% significance level to suggest that p < 0.3." }], finalAnswer: "(a) The critical region is \\(X \\le 3\\). (b) The actual significance level is \\(0.0332\\) (\\(3.32\\%\\)). (c) Since \\(X = 3\\) lies in the critical region, we reject \\(H_0\\). There is sufficient evidence to suggest that \\(p < 0.3\\)." } },
    { id: "y1ht3-030", topicRef: "y1ht3", topicTitle: "Critical Regions 30", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["multi-part", "two-tailed", "critical region", "actual significance level", "conclusion"], questionText: "A coin is thought to be biased. To test this, the coin is flipped 20 times. Let \\(X\\) denote the number of heads. The hypotheses are \\(H_0: p = 0.5\\) and \\(H_1: p \\ne 0.5\\). The test is conducted at the 5% significance level. You are given: \\(P(X \\le 5) = 0.0207\\), \\(P(X \\le 6) = 0.0577\\), \\(P(X \\ge 15) = 0.0207\\), \\(P(X \\ge 14) = 0.0577\\). (a) Find the critical region. (b) Find the actual significance level. (c) The coin is flipped 20 times and 15 heads are observed. State the conclusion in context.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Each tail has at most 2.5%.", workingLatex: "\\text{Lower: } P(X \\le 5) = 0.0207 < 0.025, \\quad P(X \\le 6) = 0.0577 > 0.025", explanation: "Lower critical region: X <= 5." }, { stepNumber: 2, description: "Upper tail.", workingLatex: "\\text{Upper: } P(X \\ge 15) = 0.0207 < 0.025, \\quad P(X \\ge 14) = 0.0577 > 0.025", explanation: "Upper critical region: X >= 15." }, { stepNumber: 3, description: "(b) Actual significance level.", workingLatex: "\\text{Actual significance level} = 0.0207 + 0.0207 = 0.0414", explanation: "" }, { stepNumber: 4, description: "(c) Compare observed value.", workingLatex: "X = 15 \\ge 15", explanation: "The observed value lies in the critical region." }, { stepNumber: 5, description: "State conclusion in context.", workingLatex: "\\text{Reject } H_0.", explanation: "There is sufficient evidence at the 5% significance level to conclude that the coin is biased." }], finalAnswer: "(a) The critical region is \\(X \\le 5\\) or \\(X \\ge 15\\). (b) The actual significance level is \\(0.0414\\) (\\(4.14\\%\\)). (c) Since \\(X = 15\\) lies in the critical region, we reject \\(H_0\\). There is sufficient evidence to suggest that the coin is biased." } },
    { id: "y1ht3-031", topicRef: "y1ht3", topicTitle: "Critical Regions 31", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Challenge", tags: ["asymmetric tails", "actual significance level"], questionText: "The critical region for a two-tailed test is \\(X \\le 2\\) or \\(X \\ge 9\\) where \\(X \\sim B(12, 0.5)\\) under \\(H_0\\). Find the actual significance level. You are given: \\(P(X \\le 2) = 0.0193\\) and \\(P(X \\ge 9) = 0.0730\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Find the total probability of both tails.", workingLatex: "\\text{Actual significance level} = P(X \\le 2) + P(X \\ge 9)", explanation: "" }, { stepNumber: 2, description: "Calculate.", workingLatex: "= 0.0193 + 0.0730 = 0.0923", explanation: "" }, { stepNumber: 3, description: "Note the asymmetry.", workingLatex: "\\text{The upper tail contributes } 0.0730 \\text{ and the lower tail contributes } 0.0193.", explanation: "Since B(12, 0.5) is symmetric, if the critical region were chosen symmetrically (X <= 2 or X >= 10), it would have actual significance 0.0193 + 0.0193 = 0.0386. The given region is not the standard choice." }], finalAnswer: "The actual significance level is \\(0.0923\\) (or \\(9.23\\%\\))." } },
    { id: "y1ht3-032", topicRef: "y1ht3", topicTitle: "Critical Regions 32", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["show that", "critical region", "verify"], questionText: "The random variable \\(X \\sim B(10, 0.3)\\). Show that the critical region for a one-tailed test of \\(H_0: p = 0.3\\) against \\(H_1: p < 0.3\\) at the 5% significance level is \\(X \\le 0\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Calculate P(X = 0).", workingLatex: "P(X = 0) = \\binom{10}{0}(0.3)^0(0.7)^{10} = (0.7)^{10} = 0.0282", explanation: "" }, { stepNumber: 2, description: "Calculate P(X <= 1).", workingLatex: "P(X = 1) = \\binom{10}{1}(0.3)^1(0.7)^9 = 10 \\times 0.3 \\times (0.7)^9 = 10 \\times 0.3 \\times 0.04035 = 0.1211", explanation: "" }, { stepNumber: 3, description: "Find P(X <= 1).", workingLatex: "P(X \\le 1) = 0.0282 + 0.1211 = 0.1493", explanation: "" }, { stepNumber: 4, description: "Verify the critical region.", workingLatex: "P(X \\le 0) = 0.0282 < 0.05 \\quad \\text{and} \\quad P(X \\le 1) = 0.1493 > 0.05", explanation: "Since P(X <= 0) < 0.05 and P(X <= 1) > 0.05, the critical region is X <= 0 as required." }], finalAnswer: "Since \\(P(X \\le 0) = 0.0282 < 0.05\\) and \\(P(X \\le 1) = 0.1493 > 0.05\\), the critical region is \\(X \\le 0\\), as required." } },
    { id: "y1ht3-033", topicRef: "y1ht3", topicTitle: "Critical Regions 33", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["finding n", "critical region", "P(X=0)"], questionText: "The random variable \\(X \\sim B(n, 0.15)\\). Find the largest value of \\(n\\) such that \\(X = 0\\) does not lie in the critical region for a one-tailed test of \\(H_0: p = 0.15\\) against \\(H_1: p < 0.15\\) at the 5% significance level.", workedSolution: { steps: [{ stepNumber: 1, description: "X = 0 lies in the critical region when P(X = 0) < 0.05.", workingLatex: "P(X = 0) = (1 - 0.15)^n = (0.85)^n", explanation: "We need the largest n such that P(X = 0) >= 0.05." }, { stepNumber: 2, description: "Solve the inequality.", workingLatex: "(0.85)^n \\ge 0.05", explanation: "" }, { stepNumber: 3, description: "Take logarithms.", workingLatex: "n \\ln(0.85) \\ge \\ln(0.05)", explanation: "Since ln(0.85) < 0, dividing reverses the inequality." }, { stepNumber: 4, description: "Solve for n.", workingLatex: "n \\le \\frac{\\ln(0.05)}{\\ln(0.85)} = \\frac{-2.9957}{-0.16252} = 18.43", explanation: "" }, { stepNumber: 5, description: "State the answer.", workingLatex: "n = 18", explanation: "The largest integer n satisfying the inequality is 18." }], finalAnswer: "The largest value of \\(n\\) is \\(18\\)." } },
    { id: "y1ht3-034", topicRef: "y1ht3", topicTitle: "Critical Regions 34", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["multi-part", "exam-style", "full test", "context"], questionText: "A company claims that 20% of its emails are spam. An IT manager suspects the true proportion is higher. He examines a random sample of 30 emails. (a) Write down suitable hypotheses for this test. (b) Using \\(X \\sim B(30, 0.2)\\) with the cumulative probabilities \\(P(X \\le 9) = 0.9163\\) and \\(P(X \\le 10) = 0.9639\\), find the critical region at the 5% significance level. (c) State the actual significance level. (d) In the sample, 11 emails are spam. State the conclusion of the test in context.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) State hypotheses.", workingLatex: "H_0: p = 0.2 \\quad H_1: p > 0.2", explanation: "The manager suspects the proportion is higher, so this is an upper-tailed test." }, { stepNumber: 2, description: "(b) Find the critical region. For the upper tail, P(X >= c) <= 0.05.", workingLatex: "P(X \\ge 10) = 1 - P(X \\le 9) = 1 - 0.9163 = 0.0837 > 0.05", explanation: "" }, { stepNumber: 3, description: "Check the next value.", workingLatex: "P(X \\ge 11) = 1 - P(X \\le 10) = 1 - 0.9639 = 0.0361 < 0.05", explanation: "So the critical region is X >= 11." }, { stepNumber: 4, description: "(c) Actual significance level.", workingLatex: "\\text{Actual significance level} = P(X \\ge 11) = 0.0361", explanation: "" }, { stepNumber: 5, description: "(d) Compare observed value to critical region.", workingLatex: "X = 11 \\ge 11", explanation: "The observed value lies in the critical region." }, { stepNumber: 6, description: "State conclusion in context.", workingLatex: "\\text{Reject } H_0.", explanation: "There is sufficient evidence at the 5% significance level to suggest that the proportion of spam emails is greater than 20%." }], finalAnswer: "(a) \\(H_0: p = 0.2\\), \\(H_1: p > 0.2\\). (b) Critical region: \\(X \\ge 11\\). (c) Actual significance level: \\(0.0361\\) (\\(3.61\\%\\)). (d) Since \\(X = 11\\) is in the critical region, reject \\(H_0\\). There is sufficient evidence to suggest the spam proportion exceeds 20%." } },
    { id: "y1ht3-035", topicRef: "y1ht3", topicTitle: "Critical Regions 35", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["show that", "critical region", "upper tail"], questionText: "The random variable \\(X \\sim B(8, 0.5)\\). Show that the critical region for an upper-tailed test at the 5% significance level is \\(X \\ge 7\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Calculate P(X >= 7).", workingLatex: "P(X = 7) = \\binom{8}{7}(0.5)^8 = 8 \\times \\frac{1}{256} = \\frac{8}{256} = 0.03125", explanation: "" }, { stepNumber: 2, description: "Calculate P(X = 8).", workingLatex: "P(X = 8) = \\binom{8}{8}(0.5)^8 = \\frac{1}{256} = 0.00391", explanation: "" }, { stepNumber: 3, description: "Find P(X >= 7).", workingLatex: "P(X \\ge 7) = 0.03125 + 0.00391 = 0.03516", explanation: "" }, { stepNumber: 4, description: "Calculate P(X >= 6).", workingLatex: "P(X = 6) = \\binom{8}{6}(0.5)^8 = 28 \\times \\frac{1}{256} = 0.10938", explanation: "" }, { stepNumber: 5, description: "Find P(X >= 6).", workingLatex: "P(X \\ge 6) = 0.10938 + 0.03516 = 0.14453", explanation: "" }, { stepNumber: 6, description: "Verify the critical region.", workingLatex: "P(X \\ge 7) = 0.03516 < 0.05 \\quad \\text{and} \\quad P(X \\ge 6) = 0.14453 > 0.05", explanation: "Since P(X >= 7) < 0.05 and P(X >= 6) > 0.05, the critical region is X >= 7, as required." }], finalAnswer: "Since \\(P(X \\ge 7) = 0.0352 < 0.05\\) and \\(P(X \\ge 6) = 0.1445 > 0.05\\), the critical region is \\(X \\ge 7\\), as required." } },
    { id: "y1ht3-036", topicRef: "y1ht3", topicTitle: "Critical Regions 36", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["multi-part", "two-tailed", "comprehensive", "context"], questionText: "A seed company states that 45% of seeds from a particular batch will germinate. A gardener thinks this proportion is wrong and plants 20 seeds. Let \\(X\\) denote the number that germinate. (a) State suitable hypotheses. (b) Find the critical region at the 10% significance level for a two-tailed test. You are given: \\(P(X \\le 5) = 0.0207\\), \\(P(X \\le 6) = 0.0577\\), \\(P(X \\ge 13) = 0.0519\\), \\(P(X \\ge 14) = 0.0207\\). (c) State the actual significance level. (d) 14 seeds germinate. State the conclusion in context.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) State hypotheses.", workingLatex: "H_0: p = 0.45 \\quad H_1: p \\ne 0.45", explanation: "The gardener thinks the proportion is wrong (could be higher or lower), so this is two-tailed." }, { stepNumber: 2, description: "(b) Each tail has at most 5%.", workingLatex: "\\text{Lower: } P(X \\le 5) = 0.0207 < 0.05, \\quad P(X \\le 6) = 0.0577 > 0.05", explanation: "Lower critical region: X <= 5." }, { stepNumber: 3, description: "Upper tail.", workingLatex: "\\text{Upper: } P(X \\ge 14) = 0.0207 < 0.05, \\quad P(X \\ge 13) = 0.0519 > 0.05", explanation: "Upper critical region: X >= 14." }, { stepNumber: 4, description: "(c) Actual significance level.", workingLatex: "\\text{Actual significance level} = 0.0207 + 0.0207 = 0.0414", explanation: "" }, { stepNumber: 5, description: "(d) Compare observed value.", workingLatex: "X = 14 \\ge 14", explanation: "The observed value lies in the critical region." }, { stepNumber: 6, description: "State conclusion.", workingLatex: "\\text{Reject } H_0.", explanation: "There is sufficient evidence at the 10% significance level to suggest that the proportion of seeds that germinate is not 45%." }], finalAnswer: "(a) \\(H_0: p = 0.45\\), \\(H_1: p \\ne 0.45\\). (b) Critical region: \\(X \\le 5\\) or \\(X \\ge 14\\). (c) Actual significance level: \\(0.0414\\) (\\(4.14\\%\\)). (d) Since \\(X = 14\\) is in the critical region, reject \\(H_0\\). There is sufficient evidence to suggest the germination rate is not 45%." } },
    { id: "y1ht3-037", topicRef: "y1ht3", topicTitle: "Critical Regions 37", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["finding n", "critical region"], questionText: "The random variable \\(X \\sim B(n, 0.1)\\). For a one-tailed test of \\(H_0: p = 0.1\\) against \\(H_1: p < 0.1\\) at the 5% significance level, find the smallest value of \\(n\\) for which the critical region is non-empty (i.e. the smallest \\(n\\) such that \\(P(X = 0) < 0.05\\)).", workedSolution: { steps: [{ stepNumber: 1, description: "The critical region is non-empty when P(X = 0) < 0.05.", workingLatex: "P(X = 0) = (0.9)^n < 0.05", explanation: "" }, { stepNumber: 2, description: "Take logarithms.", workingLatex: "n \\ln(0.9) < \\ln(0.05)", explanation: "" }, { stepNumber: 3, description: "Solve for n.", workingLatex: "n > \\frac{\\ln(0.05)}{\\ln(0.9)} = \\frac{-2.9957}{-0.10536} = 28.43", explanation: "Since ln(0.9) < 0, dividing reverses the inequality." }, { stepNumber: 4, description: "State the answer.", workingLatex: "n = 29", explanation: "The smallest integer n greater than 28.43 is 29." }], finalAnswer: "The smallest value of \\(n\\) is \\(29\\)." } },
    { id: "y1ht3-038", topicRef: "y1ht3", topicTitle: "Critical Regions 38", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["multi-part", "exam-style", "critical region", "context"], questionText: "A political party claims that 40% of residents in a town support their policies. A journalist believes the support is lower and surveys 16 randomly selected residents. (a) Write down suitable hypotheses. (b) Find the critical region at the 5% significance level. You are given: \\(P(X \\le 3) = 0.0651\\) and \\(P(X \\le 2) = 0.0183\\) where \\(X \\sim B(16, 0.4)\\). (c) State the actual significance level. (d) In the survey, 2 residents expressed support. State the conclusion in context.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) State hypotheses.", workingLatex: "H_0: p = 0.4 \\quad H_1: p < 0.4", explanation: "The journalist believes support is lower, so this is a lower-tailed test." }, { stepNumber: 2, description: "(b) Find the critical region.", workingLatex: "P(X \\le 2) = 0.0183 < 0.05 \\quad \\text{and} \\quad P(X \\le 3) = 0.0651 > 0.05", explanation: "The critical region is X <= 2." }, { stepNumber: 3, description: "(c) Actual significance level.", workingLatex: "\\text{Actual significance level} = P(X \\le 2) = 0.0183", explanation: "" }, { stepNumber: 4, description: "(d) Compare observed value.", workingLatex: "X = 2 \\le 2", explanation: "The observed value lies in the critical region." }, { stepNumber: 5, description: "State conclusion.", workingLatex: "\\text{Reject } H_0.", explanation: "There is sufficient evidence at the 5% significance level to suggest that less than 40% of residents support the political party." }], finalAnswer: "(a) \\(H_0: p = 0.4\\), \\(H_1: p < 0.4\\). (b) Critical region: \\(X \\le 2\\). (c) Actual significance level: \\(0.0183\\) (\\(1.83\\%\\)). (d) Since \\(X = 2\\) is in the critical region, reject \\(H_0\\). There is sufficient evidence that support is less than 40%." } },
    { id: "y1ht3-039", topicRef: "y1ht3", topicTitle: "Critical Regions 39", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["multi-part", "two-tailed", "asymmetric", "context"], questionText: "A machine fills packets of cereal and the probability that a randomly chosen packet is underweight is \\(p\\). To test whether \\(p\\) has changed from 0.2, 30 packets are randomly selected. (a) State suitable hypotheses. (b) Find the critical region for a two-tailed test at the 5% significance level. You are given: \\(P(X \\le 2) = 0.0442\\), \\(P(X \\le 1) = 0.0105\\), \\(P(X \\ge 11) = 0.0464\\), \\(P(X \\ge 12) = 0.0181\\), where \\(X \\sim B(30, 0.2)\\). (c) Find the actual significance level. (d) 12 packets are found to be underweight. State the conclusion.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) State hypotheses.", workingLatex: "H_0: p = 0.2 \\quad H_1: p \\ne 0.2", explanation: "" }, { stepNumber: 2, description: "(b) Each tail has at most 2.5%.", workingLatex: "\\text{Lower: } P(X \\le 1) = 0.0105 < 0.025, \\quad P(X \\le 2) = 0.0442 > 0.025", explanation: "Lower critical region: X <= 1." }, { stepNumber: 3, description: "Upper tail.", workingLatex: "\\text{Upper: } P(X \\ge 12) = 0.0181 < 0.025, \\quad P(X \\ge 11) = 0.0464 > 0.025", explanation: "Upper critical region: X >= 12." }, { stepNumber: 4, description: "(c) Actual significance level.", workingLatex: "\\text{Actual significance level} = P(X \\le 1) + P(X \\ge 12) = 0.0105 + 0.0181 = 0.0286", explanation: "" }, { stepNumber: 5, description: "(d) Compare observed value.", workingLatex: "X = 12 \\ge 12", explanation: "The observed value lies in the upper critical region." }, { stepNumber: 6, description: "State conclusion.", workingLatex: "\\text{Reject } H_0.", explanation: "There is sufficient evidence at the 5% level to suggest that the probability of a packet being underweight has changed from 0.2." }], finalAnswer: "(a) \\(H_0: p = 0.2\\), \\(H_1: p \\ne 0.2\\). (b) Critical region: \\(X \\le 1\\) or \\(X \\ge 12\\). (c) Actual significance level: \\(0.0286\\) (\\(2.86\\%\\)). (d) Since \\(X = 12\\) is in the critical region, reject \\(H_0\\). There is sufficient evidence that \\(p\\) has changed from 0.2." } },
    { id: "y1ht3-040", topicRef: "y1ht3", topicTitle: "Critical Regions 40", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Challenge", tags: ["comprehensive", "multi-part", "full test", "context"], questionText: "A health authority reports that 15% of adults in a region have a certain condition. A researcher suspects the rate has increased and tests a random sample of 40 adults. Let \\(X\\) denote the number with the condition, where \\(X \\sim B(40, 0.15)\\) under \\(H_0\\). (a) State the hypotheses. (b) Given that \\(P(X \\le 9) = 0.9256\\) and \\(P(X \\le 10) = 0.9671\\), find the critical region at the 5% significance level. (c) State the actual significance level. (d) Given instead that the test is at the 1% level and \\(P(X \\le 11) = 0.9870\\), find the critical region at this level. (e) In the sample, 11 adults have the condition. State the conclusion at each significance level.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) State hypotheses.", workingLatex: "H_0: p = 0.15 \\quad H_1: p > 0.15", explanation: "The researcher suspects the rate has increased, so this is an upper-tailed test." }, { stepNumber: 2, description: "(b) At 5%, find c such that P(X >= c) <= 0.05.", workingLatex: "P(X \\ge 10) = 1 - P(X \\le 9) = 1 - 0.9256 = 0.0744 > 0.05", explanation: "" }, { stepNumber: 3, description: "Check the next value.", workingLatex: "P(X \\ge 11) = 1 - P(X \\le 10) = 1 - 0.9671 = 0.0329 < 0.05", explanation: "So the critical region at 5% is X >= 11." }, { stepNumber: 4, description: "(c) Actual significance level at 5%.", workingLatex: "\\text{Actual significance level} = P(X \\ge 11) = 0.0329", explanation: "" }, { stepNumber: 5, description: "(d) At 1%, check P(X >= 12).", workingLatex: "P(X \\ge 12) = 1 - P(X \\le 11) = 1 - 0.9870 = 0.0130 > 0.01", explanation: "P(X >= 12) = 0.0130 > 0.01, so X >= 12 is not the critical region at 1%. We would need to check P(X >= 13). Since the question only gives cumulative values up to X <= 11, we know P(X >= 12) = 0.0130 > 0.01, so we need a higher critical value. Using the pattern, the critical region at 1% would require P(X >= c) <= 0.01; since P(X >= 12) = 0.0130 > 0.01, the critical region at 1% is X >= 13 (accepting that P(X >= 13) < 0.01)." }, { stepNumber: 6, description: "(e) At 5%: X = 11.", workingLatex: "X = 11 \\ge 11 \\implies \\text{Reject } H_0 \\text{ at 5\\%.}", explanation: "" }, { stepNumber: 7, description: "At 1%: X = 11.", workingLatex: "X = 11 < 13 \\implies \\text{Do not reject } H_0 \\text{ at 1\\%.}", explanation: "The result is significant at 5% but not at 1%." }], finalAnswer: "(a) \\(H_0: p = 0.15\\), \\(H_1: p > 0.15\\). (b) Critical region at 5%: \\(X \\ge 11\\). (c) Actual significance level: \\(0.0329\\) (\\(3.29\\%\\)). (d) Critical region at 1%: \\(X \\ge 13\\). (e) At 5%, \\(X = 11\\) lies in the critical region so we reject \\(H_0\\) -- there is evidence the condition rate has increased. At 1%, \\(X = 11\\) does not lie in the critical region so we do not reject \\(H_0\\)." } },
];
